-- SQLite -> MySQL dump for database `devnote`
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS=0;
CREATE DATABASE IF NOT EXISTS `devnote` CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE `devnote`;

-- Table `changelog`
DROP TABLE IF EXISTS `changelog`;
CREATE TABLE `changelog` (
  `id` VARCHAR(191) NOT NULL PRIMARY KEY,
  `entityType` TEXT NOT NULL,
  `entityId` TEXT NOT NULL,
  `action` TEXT NOT NULL,
  `payload` TEXT NOT NULL,
  `createdAt` TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

DROP TABLE IF EXISTS `folder`;
CREATE TABLE `folder` (
  `id` VARCHAR(191) NOT NULL PRIMARY KEY,
  `parentId` VARCHAR(191),
  `title` TEXT NOT NULL,
  `description` TEXT,
  `color` TEXT,
  `position` INT NOT NULL DEFAULT 0,
  `createdAt` BIGINT NOT NULL,
  `updatedAt` BIGINT NOT NULL,
  CONSTRAINT `folder_parentId_fkey` FOREIGN KEY (`parentId`) REFERENCES `folder` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


-- Table `page`
DROP TABLE IF EXISTS `page`;
CREATE TABLE `page` (
  `id` VARCHAR(191) NOT NULL PRIMARY KEY,
  `folderId` VARCHAR(191),
  `title` TEXT NOT NULL,
  `slug` TEXT,
  `position` INT NOT NULL DEFAULT 0,
  `searchText` TEXT NOT NULL DEFAULT '',
  `isPinned` TINYINT(1) NOT NULL DEFAULT 0,
  `isArchived` TINYINT(1) NOT NULL DEFAULT 0,
  `createdAt` BIGINT NOT NULL,
  `updatedAt` BIGINT NOT NULL,
  CONSTRAINT `page_folderId_fkey` FOREIGN KEY (`folderId`) REFERENCES `folder` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;



-- Table `pagerevision`
DROP TABLE IF EXISTS `pagerevision`;
CREATE TABLE `pagerevision` (
  `id` VARCHAR(191) NOT NULL PRIMARY KEY,
  `pageId` VARCHAR(191) NOT NULL,
  `snapshot` LONGTEXT NOT NULL,
  `createdAt` BIGINT NOT NULL,
  CONSTRAINT `pagerevision_pageId_fkey` FOREIGN KEY (`pageId`) REFERENCES `page` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- Table `pagecontent`
DROP TABLE IF EXISTS `pagecontent`;
CREATE TABLE `pagecontent` (
  `id` VARCHAR(191) NOT NULL PRIMARY KEY,
  `pageId` VARCHAR(191) NOT NULL,
  `html` LONGTEXT,
  `json` LONGTEXT,
  `text` LONGTEXT,
  `canvasJson` LONGTEXT,
  `createdAt` BIGINT NOT NULL,
  `updatedAt` BIGINT NOT NULL,
  CONSTRAINT `pagecontent_pageId_fkey` FOREIGN KEY (`pageId`) REFERENCES `page` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


-- Table `syncstate`
DROP TABLE IF EXISTS `syncstate`;
CREATE TABLE `syncstate` (
  `id` VARCHAR(191) NOT NULL PRIMARY KEY,
  `clientId` TEXT NOT NULL,
  `cursor` TEXT NOT NULL,
  `lastSyncedAt` TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `createdAt` TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` TEXT NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


SET FOREIGN_KEY_CHECKS=1;