INSERT INTO `page` (`id`, `folderId`, `title`, `slug`, `position`, `searchText`, `isPinned`, `isArchived`, `createdAt`, `updatedAt`) VALUES ('cmgouqvla00sd3rqpykdbe36e', 'cmgouqsqq00s93rqpsjxtk22d', 'Notities', NULL, 0, 'startscherm in de PCF maken waar knelpunten liggen:Niet ingeplande leistungenOok voor min uren, overschrijdende uren en niet bezette urenMeldungen van een leistung onder de leistung laten zien.Ook niet geplande leistungen laten zien.Automatisch medewerker aanstellen voor demo laten zien metMedewerker is al vaker voor die soort leistung aangesteld en werkt in dat postcode gebied.Extra veld voor afwijkende urenregistraties.Echt beginnen met dashboard bij PCFAantal leistungen nicht gepland in Dashboard 1e tabAantal volgeplande leistungenBij leistung view ook mitarbeiters in kunnen plannen.Icoontjes laten zien bij medewerkerin formulier ook machines kunnen plannen.Planregels op 1e dag van de week komen niet op plannerAutomatisch medewerker aanwijzen laten zien in Abwesenheits dashboard met knop om te accepteren.Machine laten zien in Leistung overview per row (projectGroup calculation aanpassen.)Medewerker toevoegen in SnelformulierVertalingen fixen.meldingen laten zien dat je een planregel niet in kan plannen omdat een medewerker afwezig isvervangen planregels nog kunnen zien in Abwesenheits dashboardAls er al een planitem gepland staat op een afwezigheidsdag word de afwezigheids niet weergevenRechtsbovenin sidebar medewerker laten zien dat een medewerker afwezig is of niet.Uitklappen na klikken op gepland/ ongepland in Dashboard.Gepland status met bolletje aantonen bij leistungBerekeningen nalopen dashbaord.Op dashboard blijft afwezige medewerkers nog urgent staan.Leistungen met min-uren.Als 1 van alle medewerkers op dashboard nog niet vervangen is komt alles in het rood.Als medewerker ziek is en nog niet is ingeplanned staat er geen rode kleur oid.', 0, 0, 1760342958191, 1761662179463);
INSERT INTO `page` (`id`, `folderId`, `title`, `slug`, `position`, `searchText`, `isPinned`, `isArchived`, `createdAt`, `updatedAt`) VALUES ('cmgp1y0as00u53rqpfwddo0kj', 'cmgp1xwy000u13rqpf8l0j5at', 'Notities', NULL, 0, 'Beide dashboards splitsen in 2 PCFsAccountmanagerPotentieel volume ervoor zetten in verkooppijplijn per fase.Gemiddeld Potentieel volume gebruiken in main card headerBM Realisatie mag weg.2 nieuwe buttons die naar power bi linkenKKM overzicht: https://royalkoopmans-acc.crm4.dynamics.com/main.aspx?appid=18ea47ea-9b55-f011-877b-6045bd95a6af&newWindow=true&pagetype=dashboard&id=b96e1dcc-c6ca-f011-bbd3-6045bd8d96ef&type=systemContracten: https://royalkoopmans-acc.crm4.dynamics.com/main.aspx?appid=18ea47ea-9b55-f011-877b-6045bd95a6af&newWindow=true&pagetype=dashboard&id=29fa1bff-c6ca-f011-bbd3-7ced8d11537c&type=systemRecente contactmomenten mogen weg, dan een button met aantal Recente Verslagen en die linkt naar dynamics overview zelf.Verkooppijplijn per fase gebruikt nog niet de correcte fases.Contractstatus mag wegBTA Dashboard:BTA Activiteiten en BTA KPI\'s mogen wegAlerts & prioriteiten moeten erbij (Moeten alleen taken bevatten van de huidige week.)Gekoppelde Verkooppijplijn wrapper moet wegde knop voor Verkooppijplijn per Fase met text Volledig overzicht moet naar een detailpagina van verkoopkansen leiden, daar moet je kunnen filteren tussen:KlantVolumeExtra tabje met klachten:Hier moet je kunnen filteren op klant.', 0, 0, 1760355048196, 1765748942840);
