INSERT INTO `page` (`id`, `folderId`, `title`, `slug`, `position`, `searchText`, `isPinned`, `isArchived`, `createdAt`, `updatedAt`) VALUES ('cmgumufil00wi3rqp7edbwwn3', 'cmgj32oxs00ic3rqp2pj5mm1k', '20-10-2025', NULL, 1, 'Cube gaat een endpoint voor ons aanmaken, alleen daar is een IP whitelist voor nodig.Microsoft stuurt vanuit meerdere IP-addressen requests, dus is hier een Azure-omgeving voor nodig om dit te bundelen.Vanuit hier moet een connectie worden opgesteld om de access tokens op te halen vanuit cube, dan kunnen we verder met de impersonate functie voor de PCF component.Alternatief hiervoor kan zijn om de hele IP range te whitelisten.De API key voor de kadaster API is geaccepteerd en kan worden verwerkt.', 0, 0, 1760692484110, 1760694003528);
