INSERT INTO `page` (`id`, `folderId`, `title`, `slug`, `position`, `searchText`, `isPinned`, `isArchived`, `createdAt`, `updatedAt`) VALUES ('cmj6y4f5j005s1269yua2gaum', 'cmj6y3dxh005o1269bc40hewj', 'Notities', NULL, 0, 'key rule of two’s complement:The most significant bit has a negative weight8 in binary is 10008 >> 1 becomes 0100, which is 48 >> 2 becomes 0010, which is 28 in binary is 000010008 << 1 becomes 00010000, which is 1616 << 1 becomes 00100000, which is 3232 << 1 becomes 01000000, which is 6464 << 1 becomes 10000000, which is 128& 1 zorgt ervoor dat je altijd 0 of 1 terugkrijgt, ongeacht wat er verder in de byte staat.', 0, 0, 1765790584760, 1765802101063);
