INSERT INTO `pagecontent` (`id`, `pageId`, `html`, `json`, `text`, `canvasJson`, `createdAt`, `updatedAt`) VALUES ('cmgj32w9l00ik3rqpxgbwzivl', 'cmgj32vje00ig3rqp5bbkk9ub', '<ul><li><p>Manier vinden om CMS Impersonate functie te verwerken. Ze willen graag het dashboard van <a target="_blank" rel="noopener noreferrer nofollow" href="http://pure-energie.nl">pure-energie.nl</a> kunnen zien binnen een Dynamics tab op een Account veld.</p><ul><li><p>Token achterhalen voor impersonate functie, deze eventueel in account veld opslaan.</p></li><li><p>Deze token ligt niet bij Pure, maar waarschijnlijk bij Cube (Externe Partij)</p></li><li><p>Mark gaat de vraag uitstellen hoe we aan dat token komen aan Cube, dat zal hij mij laten weten als hier reactie op is.</p></li><li><p><a target="_blank" rel="noopener noreferrer nofollow" href="https://dmp.pure-energie.nl/api/klantportaal/customer">https://dmp.pure-energie.nl/api/klantportaal/customer</a></p></li><li><p><a target="_blank" rel="noopener noreferrer nofollow" href="https://pure-energie.nl/mijn/inloggen/?access=54e7d709-6fef-4e41-b669-097daff0366f">https://pure-energie.nl/mijn/inloggen/?access=54e7d709-6fef-4e41-b669-097daff0366f</a></p></li><li><p><a target="_blank" rel="noopener noreferrer nofollow" href="https://dmp.pure-energie.nl/app/impersonate/679829d5-471c-4372-a2aa-b173398186ef">https://dmp.pure-energie.nl/app/impersonate/679829d5-471c-4372-a2aa-b173398186ef</a></p></li></ul></li><li><p>Eventuele klanten van pure bij een paneel een mogelijkheid geven om contactpersonen op te geven en te synchroniseren richting Dynamics.</p></li><li><p>Test Account Raoul Adres</p><ul><li><p>Klantnummer: 191078</p></li><li><p>Verenlandweg 12, 7461AP Rijssen</p></li></ul></li><li><p><a target="_blank" rel="noopener noreferrer nofollow" href="https://formulieren.kadaster.nl/aanvraag_bag_api_individuele_bevragingen_productie">https://formulieren.kadaster.nl/aanvraag_bag_api_individuele_bevragingen_productie</a></p></li><li><p>Custom velden beginnen allemaal met RH</p></li><li><p>Accounts worden voor nu nog niet verwijderd, alleen op inactief gezet.</p></li></ul>', '{"type":"doc","content":[{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Manier vinden om CMS Impersonate functie te verwerken. Ze willen graag het dashboard van "},{"type":"text","marks":[{"type":"link","attrs":{"href":"http://pure-energie.nl","target":"_blank","rel":"noopener noreferrer nofollow","class":null}}],"text":"pure-energie.nl"},{"type":"text","text":" kunnen zien binnen een Dynamics tab op een Account veld."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Token achterhalen voor impersonate functie, deze eventueel in account veld opslaan."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Deze token ligt niet bij Pure, maar waarschijnlijk bij Cube (Externe Partij)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Mark gaat de vraag uitstellen hoe we aan dat token komen aan Cube, dat zal hij mij laten weten als hier reactie op is."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"link","attrs":{"href":"https://dmp.pure-energie.nl/api/klantportaal/customer","target":"_blank","rel":"noopener noreferrer nofollow","class":null}}],"text":"https://dmp.pure-energie.nl/api/klantportaal/customer"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"link","attrs":{"href":"https://pure-energie.nl/mijn/inloggen/?access=54e7d709-6fef-4e41-b669-097daff0366f","target":"_blank","rel":"noopener noreferrer nofollow","class":null}}],"text":"https://pure-energie.nl/mijn/inloggen/?access=54e7d709-6fef-4e41-b669-097daff0366f"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"link","attrs":{"hre