INSERT INTO `pagecontent` (`id`, `pageId`, `html`, `json`, `text`, `canvasJson`, `createdAt`, `updatedAt`) VALUES ('cmgkklmtn00s13rqp6q4jdnzj', 'cmgkkl0iq00rx3rqp6h7jje5x', '<ul><li><p><s>Ooit nog een keer dotenv verwerken in de nieuwe API</s></p></li></ul>', '{"type":"doc","content":[{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Ooit nog een keer dotenv verwerken in de nieuwe API"}]}]}]}]}', 'Ooit nog een keer dotenv verwerken in de nieuwe API', NULL, 1760084052683, 1764846187713);
INSERT INTO `pagecontent` (`id`, `pageId`, `html`, `json`, `text`, `canvasJson`, `createdAt`, `updatedAt`) VALUES ('cmgourisp00sh3rqp80xjpys7', 'cmgouqvla00sd3rqpykdbe36e', '<ul><li><p><s>startscherm in de PCF maken waar knelpunten liggen:</s></p><ul><li><p><s>Niet ingeplande leistungen</s></p></li><li><p><s>Ook voor min uren, overschrijdende uren en niet bezette uren</s></p></li></ul></li><li><p><s>Meldungen van een leistung onder de leistung laten zien.</s></p></li><li><p><s>Ook niet geplande leistungen laten zien.</s></p></li><li><p><s>Automatisch medewerker aanstellen voor demo laten zien met</s></p><ul><li><p><s>Medewerker is al vaker voor die soort leistung aangesteld en werkt in dat postcode gebied.</s></p></li></ul></li><li><p><s>Extra veld voor afwijkende urenregistraties.</s></p></li><li><p><s>Echt beginnen met dashboard bij PCF</s></p></li><li><p><s>Aantal leistungen nicht gepland in Dashboard 1e tab</s></p></li><li><p><s>Aantal volgeplande leistungen</s></p></li><li><p><s>Bij leistung view ook mitarbeiters in kunnen plannen.</s></p><ul><li><p><s>Icoontjes laten zien bij medewerker</s></p></li></ul></li><li><p><s>in formulier ook machines kunnen plannen.</s></p></li><li><p><s>Planregels op 1e dag van de week komen niet op planner</s></p></li><li><p><s>Automatisch medewerker aanwijzen laten zien in Abwesenheits dashboard met knop om te accepteren.</s></p></li><li><p><s>Machine laten zien in Leistung overview per row (projectGroup calculation aanpassen.)</s></p></li><li><p><s>Medewerker toevoegen in Snelformulier</s></p></li><li><p><s>Vertalingen fixen.</s></p></li><li><p><s>meldingen laten zien dat je een planregel niet in kan plannen omdat een medewerker afwezig is</s></p></li><li><p><s>vervangen planregels nog kunnen zien in Abwesenheits dashboard</s></p></li><li><p><s>Als er al een planitem gepland staat op een afwezigheidsdag word de afwezigheids niet weergeven</s></p></li><li><p><s>Rechtsbovenin sidebar medewerker laten zien dat een medewerker afwezig is of niet.</s></p></li><li><p><s>Uitklappen na klikken op gepland/ ongepland in Dashboard.</s></p></li><li><p><s>Gepland status met bolletje aantonen bij leistung</s></p></li><li><p><s>Berekeningen nalopen dashbaord.</s></p></li><li><p><s>Op dashboard blijft afwezige medewerkers nog urgent staan.</s></p></li><li><p><s>Leistungen met min-uren.</s></p></li><li><p><s>Als 1 van alle medewerkers op dashboard nog niet vervangen is komt alles in het rood.</s></p></li><li><p><s>Als medewerker ziek is en nog niet is ingeplanned staat er geen rode kleur oid.</s></p></li></ul>', '{"type":"doc","content":[{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"startscherm in de PCF maken waar knelpunten liggen:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Niet ingeplande leistungen"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Ook voor min uren, overschrijdende uren en niet bezette uren"}]}]}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Meldungen van een leistung onder de leistung laten zien."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Ook niet geplande leistungen laten zien."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Automatisch medewerker aanstellen voor demo laten zien met"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Medewerker is al vaker voor die soort leistung aangesteld en werkt in dat postcode gebied."}]}]}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Extra veld voor afwijkende urenregistraties."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Echt beginnen met dashboard bij PCF"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Aantal leistungen nicht gepland in Dashboard 1e tab"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Aantal volgeplande leistungen"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Bij leistung view ook mitarbeiters in kunnen plannen."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Icoontjes laten zien bij medewerker"}]}]}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"in formulier ook machines kunnen plannen."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Planregels op 1e dag van de week komen niet op planner"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Automatisch medewerker aanwijzen laten zien in Abwesenheits dashboard met knop om te accepteren."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Machine laten zien in Leistung overview per row (projectGroup calculation aanpassen.)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Medewerker toevoegen in Snelformulier"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Vertalingen fixen."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"meldingen laten zien dat je een planregel niet in kan plannen omdat een medewerker afwezig is"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"vervangen planregels nog kunnen zien in Abwesenheits dashboard"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Als er al een planitem gepland staat op een afwezigheidsdag word de afwezigheids niet weergeven"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Rechtsbovenin sidebar medewerker laten zien dat een medewerker afwezig is of niet."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Uitklappen na klikken op gepland/ ongepland in Dashboard."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Gepland status met bolletje aantonen bij leistung"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Berekeningen nalopen dashbaord."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Op dashboard blijft afwezige medewerkers nog urgent staan."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Leistungen met min-uren."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Als 1 van alle medewerkers op dashboard nog niet vervangen is komt alles in het rood."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Als medewerker ziek is en nog niet is ingeplanned staat er geen rode kleur oid."}]}]}]}]}', 'startscherm in de PCF maken waar knelpunten liggen:Niet ingeplande leistungenOok voor min uren, overschrijdende uren en niet bezette urenMeldungen van een leistung onder de leistung laten zien.Ook niet geplande leistungen laten zien.Automatisch medewerker aanstellen voor demo laten zien metMedewerker is al vaker voor die soort leistung aangesteld en werkt in dat postcode gebied.Extra veld voor afwijkende urenregistraties.Echt beginnen met dashboard bij PCFAantal leistungen nicht gepland in Dashboard 1e tabAantal volgeplande leistungenBij leistung view ook mitarbeiters in kunnen plannen.Icoontjes laten zien bij medewerkerin formulier ook machines kunnen plannen.Planregels op 1e dag van de week komen niet op plannerAutomatisch medewerker aanwijzen laten zien in Abwesenheits dashboard met knop om te accepteren.Machine laten zien in Leistung overview per row (projectGroup calculation aanpassen.)Medewerker toevoegen in SnelformulierVertalingen fixen.meldingen laten zien dat je een planregel niet in kan plannen omdat een medewerker afwezig isvervangen planregels nog kunnen zien in Abwesenheits dashboardAls er al een planitem gepland staat op een afwezigheidsdag word de afwezigheids niet weergevenRechtsbovenin sidebar medewerker laten zien dat een medewerker afwezig is of niet.Uitklappen na klikken op gepland/ ongepland in Dashboard.Gepland status met bolletje aantonen bij leistungBerekeningen nalopen dashbaord.Op dashboard blijft afwezige medewerkers nog urgent staan.Leistungen met min-uren.Als 1 van alle medewerkers op dashboard nog niet vervangen is komt alles in het rood.Als medewerker ziek is en nog niet is ingeplanned staat er geen rode kleur oid.', '{"elements":[],"appState":{"viewBackgroundColor":"rgb(2 6 23 / 1)"},"files":{}}', 1760342988265, 1761662179464);
