INSERT INTO `pagecontent` (`id`, `pageId`, `html`, `json`, `text`, `canvasJson`, `createdAt`, `updatedAt`) VALUES ('cmgumvamm00wm3rqpduqqsvzt', 'cmgumufil00wi3rqp7edbwwn3', '<ul><li><p>Cube gaat een endpoint voor ons aanmaken, alleen daar is een IP whitelist voor nodig.</p><ul><li><p>Microsoft stuurt vanuit meerdere IP-addressen requests, dus is hier een Azure-omgeving voor nodig om dit te bundelen.</p></li><li><p>Vanuit hier moet een connectie worden opgesteld om de access tokens op te halen vanuit cube, dan kunnen we verder met de impersonate functie voor de PCF component.</p></li><li><p>Alternatief hiervoor kan zijn om de hele IP range te whitelisten.</p></li></ul></li><li><p>De API key voor de kadaster API is geaccepteerd en kan worden verwerkt.</p></li></ul>', '{"type":"doc","content":[{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Cube gaat een endpoint voor ons aanmaken, alleen daar is een IP whitelist voor nodig."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Microsoft stuurt vanuit meerdere IP-addressen requests, dus is hier een Azure-omgeving voor nodig om dit te bundelen."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Vanuit hier moet een connectie worden opgesteld om de access tokens op te halen vanuit cube, dan kunnen we verder met de impersonate functie voor de PCF component."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Alternatief hiervoor kan zijn om de hele IP range te whitelisten."}]}]}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"De API key voor de kadaster API is geaccepteerd en kan worden verwerkt."}]}]}]}]}', 'Cube gaat een endpoint voor ons aanmaken, alleen daar is een IP whitelist voor nodig.Microsoft stuurt vanuit meerdere IP-addressen requests, dus is hier een Azure-omgeving voor nodig om dit te bundelen.Vanuit hier moet een connectie worden opgesteld om de access tokens op te halen vanuit cube, dan kunnen we verder met de impersonate functie voor de PCF component.Alternatief hiervoor kan zijn om de hele IP range te whitelisten.De API key voor de kadaster API is geaccepteerd en kan worden verwerkt.', '{"elements":[{"id":"y8ffM-5C-4TQ3UKpiwRkZ","type":"rectangle","x":439,"y":133.6000213623047,"width":244.79998779296875,"height":146.39999389648438,"angle":0,"strokeColor":"#1e1e1e","backgroundColor":"transparent","fillStyle":"solid","strokeWidth":2,"strokeStyle":"solid","roughness":1,"opacity":100,"groupIds":[],"frameId":null,"roundness":{"type":3},"seed":1031653997,"version":18,"versionNonce":53099213,"isDeleted":false,"boundElements":null,"updated":1760692541409,"link":null,"locked":false}],"appState":{"showWelcomeScreen":true,"theme":"light","currentChartType":"bar","currentItemBackgroundColor":"transparent","currentItemEndArrowhead":"arrow","currentItemFillStyle":"solid","currentItemFontFamily":1,"currentItemFontSize":20,"currentItemOpacity":100,"currentItemRoughness":1,"currentItemStartArrowhead":null,"currentItemStrokeColor":"#1e1e1e","currentItemRoundness":"round","currentItemStrokeStyle":"solid","currentItemStrokeWidth":2,"currentItemTextAlign":"left","cursorButton":"up","activeEmbeddable":null,"draggingElement":null,"editingElement":null,"editingGroupId":null,"editingLinearElement":null,"activeTool":{"type":"selection","customType":null,"locked":false,"lastActiveTool":null},"penMode":false,"penDetected":false,"errorMessage":null,"exportBackground":true,"exportScale":1,"exportEmbedScene":false,"exportWithDarkMode":false,"fileHandle":null,"gridSize":null,"isBindingEnabled":true,"defaultSidebarDockedPreference":false,"isLoading":false,"isResizing":false,"isRotating":false,"lastPointerDownWith":"mouse","multiElement":null,"name":"Untitled-2025-10-17-1115","contextMenu":null,"openMenu":null,"openPopup":null,"openSidebar":null,"openDialog":null,"pasteDialog":{"shown":false,"data":null},"previousSelectedElementIds":{"y8ffM-5C-4TQ3UKpiwRkZ":true},"resizingElement":null,"scrolledOutside":false,"scrollX":0,"scrollY":0,"selectedElementIds":{},"selectedGroupIds":{},"selectedElementsAreBeingDragged":false,"selectionElement":null,"shouldCacheIgnoreZoom":false,"showStats":false,"startBoundElement":null,"suggestedBindings":[],"frameRendering":{"enabled":true,"clip":true,"name":true,"outline":true},"frameToHighlight":null,"editingFrame":null,"elementsToHighlight":null,"toast":null,"viewBackgroundColor":"#ffffff","zenModeEnabled":false,"zoom":{"value":1},"viewModeEnabled":false,"pendingImageElementId":null,"showHyperlinkPopup":false,"selectedLinearElement":null,"snapLines":[],"originSnapOffset":null,"objectsSnapModeEnabled":false,"offsetLeft":320,"offsetTop":143.1999969482422,"width":1162.4000244140625,"height":552},"files":{}}', 1760692524430, 1760694003529);
INSERT INTO `pagecontent` (`id`, `pageId`, `html`, `json`, `text`, `canvasJson`, `createdAt`, `updatedAt`) VALUES ('cmh0co1m200yb3rqpdsfbsiu8', 'cmh0cncoy00y73rqpkb1jssen', '<ul><li><p><s>Na opzetten van Azure omgeving in de flow: "Import Artikelen/Prijslijsten", fetch translations in de product update en create zetten.</s></p></li><li><p><s>Volgnummer aanpassen naar decimale value in plaats van tekst value</s></p></li></ul>', '{"type":"doc","content":[{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Na opzetten van Azure omgeving in de flow: \\"Import Artikelen/Prijslijsten\\", fetch translations in de product update en create zetten."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"strike"}],"text":"Volgnummer aanpassen naar decimale value in plaats van tekst value"}]}]}]}]}', 'Na opzetten van Azure omgeving in de flow: "Import Artikelen/Prijslijsten", fetch translations in de product update en create zetten.Volgnummer aanpassen naar decimale value in plaats van tekst value', NULL, 1761038187050, 1763161850108);
INSERT INTO `pagecontent` (`id`, `pageId`, `html`, `json`, `text`, `canvasJson`, `createdAt`, `updatedAt`) VALUES ('cmh1qqhyj01063rqpo53zl8mu', 'cmh0m5qsw00zz3rqpy3lvqp6a', '<ul><li><p><s>Dashboard:</s></p><ul><li><p><s>Logo rechtsboven boven titel</s></p></li><li><p><s>Onder Sales cockpit: Goeiemorgen {gebruiker}</s></p></li><li><p><s>Openstaande offertes border kleur van paars naar groen</s></p></li><li><p><s>Bij openstaande offertes het volgende laten zien:</s></p><ul><li><p><s>Offertes verlopen (uitroepteken en rode tekst)</s></p></li><li><p><s>Offertes die bijna verlopen (Oranje tekst)</s></p></li><li><p><s>Gemiddelde dagen open (zwarte tekst)</s></p></li><li><p><s>Sales Cockpit -&gt; Eijsink Sales Cockpit</s></p></li></ul></li><li><p><s>Vinkje als je over vierkantje heen hovert openstaande taken</s></p></li><li><p><s>Openstaande taken default background wit en met hover: #FFD6A5</s></p></li><li><p><s>Snelle acties knoppen default lichtgeel en hover donker.</s></p></li><li><p><s>Bekijk details weghalen en dan Eijsink vierkantje er neerzetten (linksonder heeft voorkeur)</s></p></li><li><p><s>Logos de zelfde kleur als top border</s></p></li><li><p><s>Icoontjes snelle acties aanpassen</s></p></li><li><p><s>Tekst van taakstatus zwart</s></p></li><li><p><s>Als de taak over datum is een belletje erbij zetten.</s></p></li></ul></li><li><p><s>Openstaande verkoopkansen </s></p><ul><li><p><s>een knop in het overview met Verkoopkans binnenhalen</s></p></li><li><p><s>Langer als 5 dagen in een fase = roodmaken</s></p></li><li><p><s>Afsluiten extra knop in overview</s></p></li><li><p><s>extra sectie met gewonnen verkoopkansen</s></p></li></ul></li><li><p><s>Openstaande offertes</s></p><ul><li><p><s>Kunnen filteren tussen Verlopen, Binnenkort of Actief.</s></p></li><li><p><s>Op tabelheaders klikken moet zorgen voor sortering.</s></p></li></ul></li></ul><ul><li><p><s>Gespreksverslagen:</s></p><ul><li><p><s>Teams videocall icoontje van teams gebruiken.</s></p></li><li><p><s>Een tijdsselectie bijvoegen die moet starten op de tijd van nu.</s></p></li><li><p><s>Filter voor recente activiteiten</s></p></li></ul></li><li><p><s>Klantenparaplu:</s></p><ul><li><p><s>Een knop om klant goud ja/ nee te maken</s></p></li><li><p><s>een extra filter voor goud/ zilver/ brons klanten</s></p></li><li><p><s>Een extra filter voor Hoofdaccount maximaal aantal</s></p></li></ul></li><li><p><s>Statussen verkoopkans</s></p></li><li><p><s>Verkoopkans nummer toevoegen in view en detailpage\\</s></p></li><li><p><s>Blokjes verkoopkansen minder harde kleur maken (beetje net als geel)</s></p></li><li><p><s>Detail verkoopkans ook echt naar de verkoopkans zelf kunnen</s></p></li><li><p><s>Gemiddelde tijd open verkoopkansen</s></p></li><li><p><s>Teams icoontje</s></p></li><li><p><s>Taken kunnen aanmaken</s></p></li><li><p><s>Snel lead aanmaken</s></p><ul><li><p><s>Accoutnaam</s></p></li><li><p><s>Contactpersoon</s></p></li><li><p><s>voornaam</s></p></li><li><p><s>achternaam</s></p></li><li><p><s>email</s></p></li><li><p><s>mobiel</s></p></li><li><p><s>Type kans</s></p></li><li><p><s>Onderwerp</s></p></li><li><p><s>Categorie lead</s></p></li><li><p><s>Kanaal</s></p></li></ul></li><li><p><s>Meer details over lead toevoegen</s></p></li><li><p><s>Nieuwe verkoopkans aanmmaken</s></p></li><li><p><s>gewonnen verkoopkansen (datumfilter)</s></p></li><li><p><s>zoekbalk bij taken</s></p></li><li><p><s>Klantenparaplu nalopen en fixen</s></p></li><li><p><s>Leads moeten ge(dis)kwalificeerd kunnen worden</s></p></li><li><p><s>Open lead knop moet lichtblauw (kleur eijsink)</s></p></li><li><p><s>Nieuw showroombezoek (redirect naar dynamics afspraken)</s></p></li><li><p><s>Lead toevoegen knop in leadview</s></p></li><li><p><s>Snel naar verkoopkansen in leadview</s></p></li><li><p><s>Aanmaakdatum toevoegen in Leadview (ook op kunnen filteren)</s></p></li><li><p><s>Styling fixen van verkoopkans detail</s></p></li><li><p><s>Standaard de open leads laten zien ipv Alle</s></p></li><li><p><s>Op