INSERT INTO `pagecontent` (`id`, `pageId`, `html`, `json`, `text`, `canvasJson`, `createdAt`, `updatedAt`) VALUES ('cmiyez1lp001f1269m1r6uxar', 'cmgp1y0as00u53rqpfwddo0kj', '<ul><li><p>Beide dashboards splitsen in 2 PCFs</p></li><li><p>Accountmanager</p><ul><li><p><s>Potentieel volume ervoor zetten in verkooppijplijn per fase.</s></p></li><li><p><s>Gemiddeld Potentieel volume gebruiken in main card header</s></p></li><li><p><strong><s>BM Realisatie </s></strong><s>mag weg.</s></p></li><li><p><s>2 nieuwe buttons die naar power bi linken</s></p><ul><li><p>KKM overzicht: <a target="_blank" rel="noopener noreferrer nofollow" href="https://royalkoopmans-acc.crm4.dynamics.com/main.aspx?appid=18ea47ea-9b55-f011-877b-6045bd95a6af&amp;newWindow=true&amp;pagetype=dashboard&amp;id=b96e1dcc-c6ca-f011-bbd3-6045bd8d96ef&amp;type=system">https://royalkoopmans-acc.crm4.dynamics.com/main.aspx?appid=18ea47ea-9b55-f011-877b-6045bd95a6af&amp;newWindow=true&amp;pagetype=dashboard&amp;id=b96e1dcc-c6ca-f011-bbd3-6045bd8d96ef&amp;type=system</a></p></li><li><p>Contracten: <a target="_blank" rel="noopener noreferrer nofollow" href="https://royalkoopmans-acc.crm4.dynamics.com/main.aspx?appid=18ea47ea-9b55-f011-877b-6045bd95a6af&amp;newWindow=true&amp;pagetype=dashboard&amp;id=29fa1bff-c6ca-f011-bbd3-7ced8d11537c&amp;type=system">https://royalkoopmans-acc.crm4.dynamics.com/main.aspx?appid=18ea47ea-9b55-f011-877b-6045bd95a6af&amp;newWindow=true&amp;pagetype=dashboard&amp;id=29fa1bff-c6ca-f011-bbd3-7ced8d11537c&amp;type=system</a></p></li></ul></li><li><p><s>Recente contactmomenten mogen weg, dan een button met aantal Recente Verslagen en die linkt naar dynamics overview zelf.</s></p></li><li><p><s>Verkooppijplijn per fase gebruikt nog niet de correcte fases.</s></p></li><li><p><strong><s>Contractstatus </s></strong><s>mag weg</s></p></li></ul></li><li><p>BTA Dashboard:</p><ul><li><p><strong><s>BTA Activiteiten </s></strong><s>en </s><strong><s>BTA KPI\'s</s></strong><s>  mogen weg</s></p></li>