INSERT INTO `pagecontent` (`id`, `pageId`, `html`, `json`, `text`, `canvasJson`, `createdAt`, `updatedAt`) VALUES ('cmj6y4o4t005w12696sqcqtqz', 'cmj6y4f5j005s1269yua2gaum', '<ul><li><p>key rule of <strong>two’s complement</strong>:</p><blockquote><p>The most significant bit has a <strong>negative weight</strong></p></blockquote></li><li><p><code>8</code> in binary is <code>1000</code></p></li><li><p><code>8 &gt;&gt; 1</code> becomes <code>0100</code>, which is <code>4</code></p></li><li><p><code>8 &gt;&gt; 2</code> becomes <code>0010</code>, which is <code>2</code></p></li><li><p><code>8</code> in binary is <code>00001000</code></p></li><li><p><code>8 &lt;&lt; 1</code> becomes <code>00010000</code>, which is <code>16</code></p></li><li><p><code>16 &lt;&lt; 1</code> becomes <code>00100000</code>, which is <code>32</code></p></li><li><p><code>32 &lt;&lt; 1</code> becomes <code>01000000</code>, which is <code>64</code></p></li><li><p><code>64 &lt;&lt; 1</code> becomes <code>10000000</code>, which is <code>128</code></p></li><li><p><code>&amp; 1</code> zorgt ervoor dat je <strong>altijd 0 of 1</strong> terugkrijgt, ongeacht wat er verder in de byte staat.</p></li></ul>', '{"type":"doc","content":[{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"key rule of "},{"type":"text","marks":[{"type":"bold"}],"text":"two’s complement"},{"type":"text","text":":"}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"The most significant bit has a "},{"type":"text","marks":[{"type":"bold"}],"text":"negative weight"}]}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"code"}],"text":"8"},{"type":"text","text":" in binary is "},{"type":"text","marks":[{"type":"code"}],"text":"1000"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"code"}],"text":"8 >> 1"},{"type":"text","text":" becomes "}